mapper.update:
update student
name = #{name}, no = #{no}, gender = #{gender}, phone = #{phone}, id_card = #{idCard}, is_college = #{isCollege}, address = #{address}, degree = #{degree}, graduation_date = #{graduationDate}, clazz_id = #{clazzId}, violation_count = #{violationCount}, violation_score = #{violationScore}, update_time = now()
where id = #{id}

mapper.select:
select s.*, c.name as clazzName
from student s
left join clazz c on s.clazz_id = c.id

    and s.name like concat('%', #{name}, '%')
    and s.no like concat('%', #{no}, '%')
    and s.gender = #{gender}
    and s.clazz_id = #{clazzId}
    and s.degree = #{degree}
    and s.graduation_date >= #{beginGraduationDate}
    and s.graduation_date <= #{endGraduationDate}

order by s.create_time desc
limit #{offset}, #{pageSize}

select count(*)
from student s

    and s.name like concat('%', #{name}, '%')
    and s.no like concat('%', #{no}, '%')
    and s.gender = #{gender}
    and s.clazz_id = #{clazzId}
    and s.degree = #{degree}
    and s.graduation_date >= #{beginGraduationDate}
    and s.graduation_date <= #{endGraduationDate}
